def bsp(node, digits):
    chain = []
    for d in digits:
        k = '_' if d == '0' else d
        if isinstance(node, dict) and k in node:
            node = node[k]
            chain.append(node.get('_', node) if isinstance(node, dict) else node)
    return chain

