        r = requests.post(f'{url}/v1/messages', headers={'x-api-key': key, 'content-type': 'application/json', 'anthropic-version': '2023-06-01'}, json={'model': model, 'max_tokens': 4096, 'messages': [{'role': 'user', 'content': prompt}]})
