class Handler(SimpleHTTPRequestHandler):
    def do_GET(self):
        if self.path == '/shell': self.send_response(200); self.send_header('Content-Type','application/json'); self.send_header('Access-Control-Allow-Origin','*'); self.end_headers(); self.wfile.write(open('shell.json','rb').read())
        elif self.path == '/': self.send_response(200); self.send_header('Content-Type','text/html'); self.end_headers(); self.wfile.write(open('ui.html','rb').read())
        else: super().do_GET()
    def do_POST(self):
        if self.path == '/input': length = int(self.headers['Content-Length']); data = json.loads(self.rfile.read(length)); open('input.json','w').write(json.dumps(data)); self.send_response(200); self.send_header('Access-Control-Allow-Origin','*'); self.end_headers(); self.wfile.write(b'ok')
        elif self.path == '/switch': block = json.load(open('shell.json')); block['6']['5'] = 'off'; json.dump(block, open('shell.json','w'), indent=1); self.send_response(200); self.send_header('Access-Control-Allow-Origin','*'); self.end_headers(); self.wfile.write(b'stopped')
    def do_OPTIONS(self): self.send_response(200); self.send_header('Access-Control-Allow-Origin','*'); self.send_header('Access-Control-Allow-Methods','GET,POST'); self.send_header('Access-Control-Allow-Headers','Content-Type'); self.end_headers()
    def log_message(self, *args): pass
def serve(): HTTPServer(('localhost', 3000), Handler).serve_forever()
threading.Thread(target=serve, daemon=True).start()
